import re
from collections import defaultdict

def count_politician_occurrences(articles, politician_names):
    # Initialize a dictionary to store counts with original name casing
    counts = {name: 0 for name in politician_names}

    # Create a mapping from lowercase name to original name for lookup
    name_map = {name.lower(): name for name in politician_names}

    for article in articles:
        # Normalize the article to lowercase and remove punctuation
        # This ensures matching is case-insensitive and ignores punctuation
        normalized_article = re.sub(r'[^\w\s]', '', article.lower())

